  /** Synonym table — normalises common phrasings into the canonical words expected by the regexes below.
   *  Applied as a single pre-pass, case-insensitive whole-word substitution, before matching. */
  const commandSynonyms = useMemo<Array<[RegExp, string | ((match: string, ...args: string[]) => string)]>>(() => [
    [/\b(?:bisect|halve|chop|slice|partition|cleave|cut\s+up)\b/gi, "split"],
    [/\b(?:cut|divide)\b/gi, "split"],
    [/\b(?:shrink|contract|pull\s+in|indent|squeeze|push\s+in)\b/gi, "inset"],
    [/\b(?:setback|set-back)\b/gi, "inset"],
    [/\b(?:offset\s+inward|inner\s+offset)\b/gi, "inset"],
    [/\b(?:round(?:ed)?\s+off|fillet|soften|smoothen)\b/gi, "round corners"],
    [/\b(?:wrap|enclose|outline|bounding\s+hull)\b/gi, "convex hull"],
    [/\b(?:skeletonise|skeletonize|spine|backbone)\b/gi, "skeleton"],
    [/\b(?:triangles?|tesselat(?:e|ion)|mesh(?:ify)?)\b/gi, "triangulate"],
    [/\b(?:quarter|fourth)\b/gi, "4 equal"],
    [/\b(?:third)\b/gi, "3 equal"],
    [/\b(?:fifth)\b/gi, "5 equal"],
    [/\b(?:sixty-forty|60-40|60\/40)\b/gi, "60:40"],
    [/\b(?:seventy-thirty|70-30|70\/30)\b/gi, "70:30"],
    [/\b(?:eighty-twenty|80-20|80\/20)\b/gi, "80:20"],
    [/\b(?:fifty-fifty|50-50|50\/50|equal\s+halves)\b/gi, "50:50"],
    [/\b(?:centre|middle)\b/gi, "center"],
    [/\b(\d+)\s*(?:centi[\- ]?met(?:re|er)s?|cms?)\b/gi, "$1 cm"],
    [/\b(\d+(?:\.\d+)?)\s*(?:met(?:re|er)s?)\b/gi, "$1 m"],
    [/\b(\d+(?:\.\d+)?)\s*(?:milli[\- ]?met(?:re|er)s?|mm)\b/gi, (_m: string, n: string) => `${(parseFloat(n) / 1000).toFixed(3)} m`],
    [/\b(\d+(?:\.\d+)?)\s*(?:feet|foot|ft)\b/gi, (_m: string, n: string) => `${(parseFloat(n) * 0.3048).toFixed(3)} m`],
    [/\b(\d+(?:\.\d+)?)\s*(?:inches?|in|″)\b/gi, (_m: string, n: string) => `${(parseFloat(n) * 0.0254).toFixed(3)} m`],
  ], []);

  /** Normalise the prompt via the synonym table. */
  const normaliseCommandPrompt = useCallback((prompt: string): string => {
    let out = ` ${prompt.toLowerCase()} `;
    for (const [pattern, replacement] of commandSynonyms) {
      out = typeof replacement === "string" ? out.replace(pattern, replacement) : out.replace(pattern, replacement);
    }
    return out.trim();
  }, [commandSynonyms]);

  /** Levenshtein distance — used to tolerate typos in keyword matching. Capped at length 24 for perf. */
  const levenshtein = useCallback((a: string, b: string): number => {
    if (a === b) return 0;
    if (a.length === 0) return b.length;
    if (b.length === 0) return a.length;
    if (a.length > 24 || b.length > 24) return 999;
    const m = a.length, n = b.length;
    let prev = new Array<number>(n + 1);
    let cur = new Array<number>(n + 1);
    for (let j = 0; j <= n; j++) prev[j] = j;
    for (let i = 1; i <= m; i++) {
      cur[0] = i;
      for (let j = 1; j <= n; j++) {
        const cost = a.charCodeAt(i - 1) === b.charCodeAt(j - 1) ? 0 : 1;
        cur[j] = Math.min(cur[j - 1] + 1, prev[j] + 1, prev[j - 1] + cost);
      }
      [prev, cur] = [cur, prev];
    }
    return prev[n];
  }, []);

